mapper.select:
SELECT s.*, ua.status FROM student s LEFT JOIN user_account ua ON s.student_id = ua.related_id AND ua.role='STUDENT' WHERE 1=1
AND (s.student_no LIKE CONCAT('%',#{keyword},'%') OR s.student_name LIKE CONCAT('%',#{keyword},'%') OR s.major LIKE CONCAT('%',#{keyword},'%') OR s.class_name LIKE CONCAT('%',#{keyword},'%'))
AND ua.status=#{status} AND (ua.status IS NULL OR ua.status = 1) ORDER BY s.create_time DESC LIMIT #{offset},#{size}
